/**
 * Noto Sans Regular — subset covering ASCII printable, Latin-1 Supplement,
 * Latin Extended A/B, Cyrillic, general punctuation, currency symbols.
 *
 * Original: https://github.com/googlefonts/noto-fonts (OFL 1.1, Apache 2.0
 * for build tooling). The subset is produced by fonttools pyftsubset.
 *
 * Why it ships in-tree: the SDK must be isomorphic, and loading a binary
 * from a URL is fine in the browser but awkward in Node. Inlining the base64
 * bytes in a .ts file works everywhere with zero filesystem dependency.
 *
 * Size: ~67 KB TTF → ~90 KB base64. To replace, run pyftsubset with the
 * same --unicodes range and re-run scripts/build-noto-subset.sh.
 */
export const NOTO_SANS_REGULAR_TTF_BASE64 =
  "";
